 1	import * as React from 'react';
 2	
 3	import { useKubevirtTranslation } from '@kubevirt-utils/hooks/useKubevirtTranslation';
 4	import { isEmpty } from '@kubevirt-utils/utils/utils';
 5	import { ExpandableSection, FormGroup, Stack, StackItem } from '@patternfly/react-core';
 6	
 7	type SupportedSnapshotVolumesListProps = {
 8	  supportedVolumes: any[];
 9	};
10	
11	const SnapshotSupportedVolumeList: React.FC<SupportedSnapshotVolumesListProps> = ({
12	  supportedVolumes,
13	}) => {
14	  const { t } = useKubevirtTranslation();
15	  const [isExpanded, setIsExpanded] = React.useState<boolean>(false);
16	  const volumesCount = !isEmpty(supportedVolumes) ? supportedVolumes?.length : 0;
17	  const volumeCountMsg = t('Disks included in this snapshot ({{volumes}})', {
18	    volumes: volumesCount,
19	  });
20	
21	  return (
22	    <FormGroup fieldId="snapshot-supported-volume-list">
23	      {volumesCount > 0 ? (
24	        <ExpandableSection
25	          isExpanded={isExpanded}
26	          onClick={() => setIsExpanded((prev) => !prev)}
27	          toggleText={volumeCountMsg}
28	        >
29	          <Stack>
30	            {supportedVolumes?.map((vol) => (
31	              <StackItem key={vol.name}>{vol.name}</StackItem>
32	            ))}
33	          </Stack>
34	        </ExpandableSection>
35	      ) : (
36	        <b>{volumeCountMsg}</b>
37	      )}
38	    </FormGroup>
39	  );
40	};
41	
42	export default SnapshotSupportedVolumeList;

